const p = msg.payload;
const key = `temps:${p.deviceId}`;
const windowSize = 5;
let window = flow.get(key) || [];
window.push(p.temperatureC);
if (window.length > windowSize) {
    window = window.slice(window.length - windowSize);
}
flow.set(key, window);
const avgTemperatureC = window.reduce((sum, value) => sum + value, 0) / window.length;
msg.payload = {
    deviceId: p.deviceId,
    timestamp: p.timestamp,
    temperatureC: p.temperatureC,
    avgTemperatureC,
    accelG: p.accelG,
    batteryVoltage: p.batteryVoltage,
    transport: p.transport,
    type: 'telemetry'
};
return msg;

const p = msg.payload;
const baseUrl = String(env.get('CLOUD_BASE_URL') || flow.get('cloudBaseUrl') || 'http://127.0.0.1:3000').replace(/\/+$/, '');
const token = String(env.get('DEVICE_TOKEN') || flow.get('deviceToken') || 'mock-token-please-rotate');
const deviceName = String(env.get('DEVICE_NAME') || flow.get('deviceName') || 'mock-gateway-01');
const ts = Date.parse(p.timestamp);
const timestamp = Number.isNaN(ts) || ts - Date.now() > 5 * 60 * 1000 ? new Date().toISOString() : new Date(ts).toISOString();

msg.url = `${baseUrl}/api/event/create`;
msg.headers = {
    'content-type': 'application/json',
    authorization: `Bearer ${token}`
};
msg.payload = {
    deviceName,
    sensorKey: 'core-accelerometer',
    type: 'tamper',
    value: p.accelG,
    message: p.message || 'Acceleration threshold exceeded',
    timestamp
};
return msg;

